package com.example.lessondesign.controller; import com.example.lessondesign.dao.*; import org.springframework.beans.factory.annotation.Autowired; import org.springframework.http.ResponseEntity; import org.springframework.web.bind.annotation.*; import java.util.*; @RestController @RequestMapping("/api/student-exercises") public class StudentExerciseController { @Autowired private StudentExerciseDao studentExerciseDao; @Autowired private EConditionDao eConditionDao; @GetMapping("/{uid}") public ResponseEntity<List<Map<String,Object>>> getByStudent(@PathVariable String uid){ return ResponseEntity.ok(studentExerciseDao.findByExerciseAndStudent(0,uid)); } @PostMapping("/save") public ResponseEntity<Map<String,Object>> saveAnswers(@RequestBody Map<String,Object> req){ Map<String,Object> r=new HashMap<>();r.put("success",true); return ResponseEntity.ok(r); } }